const output = $input.first().json.stdout;

if (output.includes('NO_BRIEFING') || !output.includes('Action Items')) {
  return []; // No briefing or no action items — skip
}

// Extract action items section from briefing.md
const lines = output.split('\n');
let inActions = false;
const items = [];

for (const line of lines) {
  if (line.includes('## Action Items')) {
    inActions = true;
    continue;
  }
  if (inActions && line.startsWith('## ')) {
    break; // Next section
  }
  if (inActions && line.startsWith('- **')) {
    items.push(line.replace(/\*\*/g, '').trim());
  }
}

if (items.length === 0) {
  return []; // No action items, skip sending
}

// Only send if there are high-priority items
const highPriority = items.filter(i => i.includes('[!!]'));
if (highPriority.length === 0) {
  return []; // No high-priority items, skip
}

const top = items.slice(0, 3);
let message = '*Action Items*\n\n';
top.forEach(n => message += `${n}\n`);

if (items.length > 3) {
  message += `\n_...and ${items.length - 3} more_`;
}

return [{ json: { message, count: items.length } }];
